# Генерация Младших Арканов
for suit, meta in SUITS.items():
    for rank in RANKS:
        vals = MEANINGS[suit][rank]
        up = vals[0]
        rev = vals[1] if len(vals) > 1 else vals[0]  # Защита от лишних элементов
        TAROT_DB.append({
            "name": f"{rank} {suit}",
            "astro": meta["astro"],
            "up": up,
            "rev": rev
        })

ZODIAC_ASTRO = {
    "овен": "Марс", "телец": "Венера", "близнецы": "Меркурий",
    "рак": "Луна", "лев": "Солнце", "дева": "Меркурий",
    "весы": "Венера", "скорпион": "Плутон", "стрелец": "Юпитер",
    "козерог": "Сатурн", "водолей": "Уран", "рыбы": "Нептун"
}

def get_card(user_id: int | None = None, zodiac: str | None = None, force_date: str | None = None, context: str = "general") -> dict:
    today = force_date or date.today().isoformat()
    pool = TAROT_DB
    if zodiac:
        zodiac = zodiac.lower().strip()
        if zodiac in ZODIAC_ASTRO:
            filtered = [c for c in pool if ZODIAC_ASTRO[zodiac] in c["astro"]]
            if filtered: pool = filtered
    seed_str = f"tarot_{context}_{user_id}_{today}"
    seed_val = int(hashlib.sha256(seed_str.encode()).hexdigest(), 16)
    rng = random.Random(seed_val)
    card = rng.choice(pool)
    is_reversed = rng.random() < 0.3
    return {"name": card["name"], "position": "перевернутая" if is_reversed else "прямая", "meaning": card["rev"] if is_reversed else card["up"], "astro": card["astro"], "date": today}

def get_random_card() -> dict:
    card = random.choice(TAROT_DB)
    is_reversed = random.random() < 0.3
    return {"name": card["name"], "position": "перевернутая" if is_reversed else "прямая", "meaning": card["rev"] if is_reversed else card["up"], "astro": card["astro"], "date": date.today().isoformat()}

def get_daily_astrology(force_date: str = None) -> dict:
    today = force_date or date.today().isoformat()
    seed_val = int(hashlib.sha256(f"astro_{today}".encode()).hexdigest(), 16)
    rng = random.Random(seed_val)
    signs = ["Овен", "Телец", "Близнецы", "Рак", "Лев", "Дева", "Весы", "Скорпион", "Стрелец", "Козерог", "Водолей", "Рыбы"]
    aspects = ["Тригон Луны и Юпитера", "Секстиль Венеры и Меркурия", "Квадрат Марса и Сатурна", "Оппозиция Солнца и Урана", "Соединение с Нептуном"]
    advices = ["День благоприятен для начинаний.", "Сосредоточьтесь на завершении дел.", "Идеален для встреч и переговоров.", "Сохраняйте гибкость перед переменами.", "Хороший день для творчества и медитации."]
    return {"moon_sign": rng.choice(signs), "aspect": rng.choice(aspects), "advice": rng.choice(advices), "date": today}

def escape_html(text: str) -> str:
    if not text: return ""
    return text.replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;").replace('"', "&quot;")

def format_daily_message(tarot_data: dict, astro_data: dict = None, zodiac_label: str = None) -> str:
    """Формирует сообщение ТОЛЬКО с картой Таро (астроблок полностью удалён)"""
    pos_emoji = "🔄" if tarot_data["position"] == "перевернутая" else "✨"
    zodiac_note = f" | <b>{escape_html(zodiac_label.capitalize())}</b>" if zodiac_label else ""
    return (
        f"🌙 <b>{escape_html(tarot_data['name'])}</b>{zodiac_note}\n"
        f"{pos_emoji} <i>Позиция:</i> {escape_html(tarot_data['position'].capitalize())}\n\n"
        f"📜 <b>Толкование:</b>\n{escape_html(tarot_data['meaning'])}"
    )